-- COMPLETA: Define el macro
DEFINE filter_and_count(data, field, value) RETURNS result {
  filtered = FILTER $data BY $field == $value;
  $result = FOREACH (GROUP filtered ALL) GENERATE COUNT(filtered) AS total;
};

users = LOAD '/datasets/users.csv' USING PigStorage(',') AS (user_id:int, name:chararray, age:int, country:chararray, signup_date:chararray);

-- Usar el macro
usa_count = filter_and_count(users, country, 'USA');
DUMP usa_count;

DEFINE top_n(relation, sort_field, n) RETURNS top_records {
  sorted = ORDER $relation BY $sort_field DESC;
  $top_records = LIMIT sorted $n;
};

sales = LOAD '/datasets/sales.csv' USING PigStorage(',') AS (sale_id:int, region:chararray, product_category:chararray, amount:float, sale_date:chararray);

top10_sales = top_n(sales, amount, 10);
DUMP top10_sales;

orders = LOAD '/datasets/orders.csv' USING PigStorage(',') AS (order_id:int, user_id:int, product:chararray, quantity:int, price:float, order_date:chararray);

-- COMPLETA: Agrupa con PARALLEL
by_product = GROUP orders BY product PARALLEL 10;

counts = FOREACH by_product GENERATE group AS product, COUNT(orders) AS num_orders;
DUMP counts;

sales = LOAD '/datasets/sales.csv' USING PigStorage(',') AS (sale_id:int, region:chararray, product_category:chararray, amount:float, sale_date:chararray);

-- COMPLETA: Ordena con PARALLEL
sorted = ORDER sales BY amount DESC PARALLEL 5;

DUMP sorted;

orders = LOAD '/datasets/orders.csv' USING PigStorage(',') AS (order_id:int, user_id:int, product:chararray, quantity:int, price:float, order_date:chararray);

by_user = GROUP orders BY user_id;

-- COMPLETA: Nested FOREACH con ORDER
result = FOREACH by_user {
  sorted_orders = ORDER orders BY order_date DESC;
  GENERATE group AS user_id, sorted_orders;
};

DUMP result;

orders = LOAD '/datasets/orders.csv' USING PigStorage(',') AS (order_id:int, user_id:int, product:chararray, quantity:int, price:float, order_date:chararray);

by_user = GROUP orders BY user_id;

result = FOREACH by_user {
  sorted = ORDER orders BY order_date DESC;
  recent = LIMIT sorted 3;
  GENERATE group AS user_id, recent;
};

DUMP result;

logs = LOAD '/datasets/server-logs.csv' USING PigStorage(',') AS (timestamp:chararray, ip_address:chararray, request_path:chararray, status_code:int, response_time_ms:int);

-- COMPLETA: Filtra errores
errors = FILTER logs BY status_code >= 400;

-- COMPLETA: Agrupa por IP y cuenta
by_ip = GROUP errors BY ip_address;
error_counts = FOREACH by_ip GENERATE group AS ip, COUNT(errors) AS num_errors;

-- Ordena por frecuencia
sorted = ORDER error_counts BY num_errors DESC;
DUMP sorted;

logs = LOAD '/datasets/server-logs.csv' USING PigStorage(',') AS (timestamp:chararray, ip_address:chararray, request_path:chararray, status_code:int, response_time_ms:int);

by_path = GROUP logs BY request_path;
avg_times = FOREACH by_path GENERATE group AS path, AVG(logs.response_time_ms) AS avg_response_time;

sorted = ORDER avg_times BY avg_response_time DESC;
DUMP sorted;

sales = LOAD '/datasets/sales.csv' USING PigStorage(',') AS (sale_id:int, region:chararray, product_category:chararray, amount:float, sale_date:chararray);

-- COMPLETA: Extrae mes (YYYY-MM)
with_month = FOREACH sales GENERATE SUBSTRING(sale_date, 0, 7) AS month, amount;

-- COMPLETA: Agrupa por mes y suma
by_month = GROUP with_month BY month;
monthly_totals = FOREACH by_month GENERATE group AS month, SUM(with_month.amount) AS total_sales;

sorted = ORDER monthly_totals BY month;
DUMP sorted;

sales = LOAD '/datasets/sales.csv' USING PigStorage(',') AS (sale_id:int, region:chararray, product_category:chararray, amount:float, sale_date:chararray);

-- COMPLETA: Agrupa por región y categoría
by_region_category = GROUP sales BY (region, product_category);

-- COMPLETA: Calcula agregaciones
aggregated = FOREACH by_region_category GENERATE 
  FLATTEN(group) AS (region, category),
  SUM(sales.amount) AS total_sales,
  COUNT(sales) AS num_transactions,
  AVG(sales.amount) AS avg_sale;

-- Ordena por total DESC
sorted = ORDER aggregated BY total_sales DESC;
top10 = LIMIT sorted 10;

DUMP top10;

users = LOAD '/datasets/users.csv' USING PigStorage(',') AS (user_id:int, name:chararray, age:int, country:chararray, signup_date:chararray);

transformed = FOREACH users GENERATE user_id, UPPER(name) as upper_name, country;
result = LIMIT transformed 10;
DUMP result;

orders = LOAD '/datasets/orders.csv' USING PigStorage(',') AS (order_id:int, user_id:int, product:chararray, amount:double, order_date:chararray);

grouped = GROUP orders BY user_id;
flattened = FOREACH grouped GENERATE group, FLATTEN(orders.product);
result = LIMIT flattened 10;
DUMP result;

orders = LOAD '/datasets/orders.csv' USING PigStorage(',') AS (order_id:int, user_id:int, product:chararray, amount:double, order_date:chararray);
grouped = GROUP orders BY user_id;
result = FOREACH grouped {
  sorted = ORDER orders BY amount DESC;
  top = LIMIT sorted 2;
  GENERATE group, top;
}
DUMP result;

users = LOAD '/datasets/users.csv' USING PigStorage(',') AS (user_id:int, name:chararray, age:int, country:chararray, signup_date:chararray);
streamed = STREAM users THROUGH `cat`;
result = LIMIT streamed 5;
DUMP result;

users = LOAD '/datasets/users.csv' USING PigStorage(',') AS (user_id:int, name:chararray, age:int, country:chararray, signup_date:chararray);
result = FOREACH users GENERATE name, REGEX_EXTRACT(name, '([A-Z][a-z]+)', 1) as first_cap;
